window.toThis = window.toThis || {};

/*
name:
    - string   → global var
    - string[] → assign each named export to global
  single:
    - true      → force default export
    - false     → full namespace
    - undefined → auto-detect (default-only vs namespace)
*/

toThis.import = (name, url, single, log = false) => eval(`import(${JSON.stringify(url)})`).then(mod => {
	if (log === true) console.log(name, "=>", mod);
	let value;
	const keys = Object.keys(mod);
	const hasOnlyDefault = keys.length === 1 && keys[0] === "default";

	if (Array.isArray(name)) {
		name.forEach(n => {
			if (n in mod) {
				globalThis[n] = mod[n];
			} else {
				throw new Error(`Export "${n}" not found in ${url}`);
			}
		});
		return mod;
	}

	if (single === true || (single === undefined && hasOnlyDefault)) {
		value = mod.default;
	} else if (single === false) {
		value = mod;
	} else {
		value = hasOnlyDefault ? mod.default : mod;
	}

	globalThis[name] = value;
	return value;
});

