var updateFunction = null
const toRun = false
const toDelay = 0

// Imports
const imports = [
	[['OrbitControls'], 'three/addons/controls/OrbitControls.js'],
];


// Script
const toWork = () => {
	const mesh_1 = this.getObjectByName("boxman.glb")
	const mesh_2 = this.getObjectByName("NewMap")
	const updaters = []

	camera.position.set(1, 2, 3)

	// Controls
	const controls = new OrbitControls(camera, renderer.domElement)
	controls.enableDamping = true
	updaters.push((e) => controls.update() )

	if(mesh_1 !== undefined && mesh_2 !== undefined) {
		mesh_2.position.y -= 1.2
		camera.lookAt(mesh_1)

		const mixer = new THREE.AnimationMixer( mesh_1 );
		const clips = mesh_1.animations;

		const clip = THREE.AnimationClip.findByName( clips, 'idle' );
		const action = mixer.clipAction( clip );
		action.play();

		updaters.push((e) => mixer.update(e.delta/1000.0) )
	}

	updateFunction = (e) => { updaters.forEach(uF => uF(e)) }
}

// Runner
if (toRun === true) imports.reduce((p, [name, url]) => p.then(() => toThis.import(name, url)), Promise.resolve()).then(() => setTimeout(toWork, toDelay));

